router.post('/vulnerable/access', (req, res) => {
  const { token } = req.body;
  let authorized = false;

  try {
    if (!token || token.length < 20)
      throw new Error('Auth service unavailable');
    authorized = true; // only set if token is valid
  } catch (err) {
    // ⚠ Error is caught and swallowed
    // authorized is still false — but the response below
    // always sends success regardless!
    console.error('Auth error:', err.message);
  }

  // ⚠ Bug: responds success even when authorized=false
  res.json({ access: 'granted', note: 'Auth error was swallowed!' });
});

